 1→import { chromium } from 'playwright';
 2→import { mkdirSync } from 'fs';
 3→
 4→const STORYBOOK_URL = process.env.STORYBOOK_URL || 'http://localhost:6099';
 5→const OUTPUT_DIR = '.storybook/screenshots';
 6→
 7→const STORIES = [
 8→  {
 9→    id: 'validation-ds-components--all-components',
10→    name: 'ds-validation-all-components',
11→  },
12→  {
13→    id: 'smoketest-ds-components--default',
14→    name: 'smoke-test',
15→  },
16→];
17→
18→async function main() {
19→  mkdirSync(OUTPUT_DIR, { recursive: true });
20→
21→  const browser = await chromium.launch();
22→  const context = await browser.newContext({
23→    viewport: { width: 480, height: 900 },
24→  });
25→  const page = await context.newPage();
26→
27→  for (const story of STORIES) {
28→    const url = `${STORYBOOK_URL}/iframe.html?id=${story.id}&viewMode=story`;
29→    console.log(`Capturing: ${story.name} → ${url}`);
30→
31→    await page.goto(url, { waitUntil: 'networkidle' });
32→    await page.waitForTimeout(2000);
33→
34→    await page.screenshot({
35→      path: `${OUTPUT_DIR}/${story.name}.png`,
36→      fullPage: true,
37→    });
38→    console.log(`  Saved: ${OUTPUT_DIR}/${story.name}.png`);
39→  }
40→
41→  await browser.close();
42→  console.log('Done!');
43→}
44→
45→main().catch(err => {
46→  console.error(err);
47→  process.exit(1);
48→});
